#!/usr/bin/perl

use strict;
use warnings;

if (!defined $ARGV[0]) {
    die "Usage: $0 filename\n";
}

open my $fh, '<', $ARGV[0] or die "Can't open '$ARGV[0]' for reading: $!";
my $text = do { local $/; <$fh> };
close $fh;

@words = split(/\s+/, $text);

my %count;
foreach (@words) {
    $count{lc($_)}++;
}

my @sorted_pairs = map { [$count{$k}, $k] } keys %count;
sort {
    $a->[0] <=> $b->[0]
} @sorted_pairs;

splice @sorted_pairs, 0, 3;

for my $pair (@sorted_pairs) {
    print "$pair[1]: $pair[0]\n";
}

#!/usr/bin/perl
use strict;
use warnings;

if (@ARGV < 1) {
    die "Usage: $0 filename\n";
}

my $filename = shift @ARGV;

open my $fh, '<', $filename or die "$filename: can't open for reading\n";

local $/; # To slurp the entire file into memory
my $content = <$fh>;
close $fh;

# Extract email addresses using regex

my @emails = find(qr/(\b[a-zA-Z0-9_.+-]+@[a-zA-Z0-9.-]+\.[A-Za-z]{2,}\b)/i, $content);

foreach my $email (@emails) {
    print "$email\n";
}
